{
  "domain_analysis": {
    "business_context": "Order cancellation is a critical lifecycle transition in logistics. An order moves through multiple fulfillment stages — each stage changes what cancellation means operationally and financially. The spec 'users should be able to cancel their order' is dangerously underspecified: it does not define which order states permit cancellation, what happens to in-progress fulfillment, or how refunds are handled.",
    "bounded_context": "Order Management / Order Lifecycle",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A customer's request for pickup and delivery of goods, tracked through a defined lifecycle of states." },
      { "term": "Order State", "definition": "The current phase of fulfillment: e.g., PLACED, CONFIRMED, ASSIGNED, PICKED_UP, IN_TRANSIT, DELIVERED, CANCELLED." },
      { "term": "Cancellation", "definition": "A customer-initiated request to terminate an order before final delivery, subject to state-dependent rules." },
      { "term": "Cancellation Window", "definition": "The set of order states during which cancellation is permitted, and the conditions under which it is allowed." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after resources have been committed (e.g., courier assigned, goods picked up)." },
      { "term": "Refund", "definition": "The return of payment to the customer upon cancellation, potentially reduced by a cancellation fee." },
      { "term": "Courier", "definition": "The assigned driver/rider responsible for pickup and delivery of the order." },
      { "term": "Fulfillment", "definition": "The end-to-end process of picking up, transporting, and delivering goods for an order." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order can only be cancelled by the customer who placed it (or an authorized agent acting on their behalf).",
      "invariant": true,
      "invariant_justification": "Allowing unauthorized users to cancel orders is a data integrity and security violation — the system is corrupt if anyone can cancel anyone's order.",
      "testable_assertion": "A cancellation request from user X for an order owned by user Y must be rejected with an authorization error."
    },
    {
      "id": "BR-2",
      "rule": "An order that has already reached a terminal state (DELIVERED, CANCELLED) cannot be cancelled.",
      "invariant": true,
      "invariant_justification": "Terminal states are irreversible by definition. Cancelling a delivered order is a different process (return/dispute), not a cancellation. Cancelling an already-cancelled order is a no-op that would corrupt audit trails if processed twice.",
      "testable_assertion": "A cancellation request for an order in state DELIVERED or CANCELLED must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "An order in state PLACED or CONFIRMED (pre-assignment) may be cancelled with a full refund and no fee.",
      "invariant": false,
      "invariant_justification": "The fee-free window is a business policy decision that could change based on competitive pressure or margin targets.",
      "testable_assertion": "When an order in state PLACED or CONFIRMED is cancelled, the refund amount equals the original payment amount and cancellation fee is zero."
    },
    {
      "id": "BR-4",
      "rule": "An order in state ASSIGNED (courier assigned but not yet picked up) may be cancelled, but a cancellation fee applies to compensate the courier for wasted effort.",
      "invariant": false,
      "invariant_justification": "The fee amount and whether a fee applies at all is a policy decision, not a physical or data-integrity constraint.",
      "testable_assertion": "When an order in state ASSIGNED is cancelled, a cancellation fee is deducted from the refund amount, and the courier is notified of the cancellation."
    },
    {
      "id": "BR-5",
      "rule": "An order in state PICKED_UP or IN_TRANSIT (goods are physically with the courier) cannot be cancelled through self-service — it requires support intervention.",
      "invariant": false,
      "invariant_justification": "This is a policy guard, not a physical law. A business could decide to allow mid-transit cancellation with a return-to-sender flow. But by default, once goods are in motion, unilateral cancellation creates an orphaned physical package problem.",
      "testable_assertion": "A cancellation request for an order in state PICKED_UP or IN_TRANSIT must be rejected with a message directing the user to contact support."
    },
    {
      "id": "BR-6",
      "rule": "Every cancellation must produce an auditable event recording: who cancelled, when, from which state, refund amount, and fee applied.",
      "invariant": true,
      "invariant_justification": "Financial and operational audit trails are non-negotiable for dispute resolution, regulatory compliance, and fraud detection. A cancellation without a record is system corruption.",
      "testable_assertion": "After a successful cancellation, an OrderCancelled event exists with fields: orderId, cancelledBy, cancelledAt, previousState, refundAmount, cancellationFee."
    },
    {
      "id": "BR-7",
      "rule": "When an assigned order is cancelled, the courier must be notified immediately so they do not perform a wasted pickup.",
      "invariant": true,
      "invariant_justification": "Failing to notify the courier means they physically travel to a pickup that no longer exists — this is a real-world integrity failure, not just a policy preference.",
      "testable_assertion": "When an order in state ASSIGNED is cancelled, a notification is dispatched to the assigned courier within the same transaction or saga."
    },
    {
      "id": "BR-8",
      "rule": "Cancellation must be idempotent — repeated cancellation requests for the same order must not create duplicate refunds or duplicate events.",
      "invariant": true,
      "invariant_justification": "Double-refunding is financial corruption. Double-eventing pollutes audit logs. This is a data integrity constraint.",
      "testable_assertion": "A second cancellation request for an already-cancelled order returns success (idempotent) but does not trigger a second refund or a second OrderCancelled event."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An order in state PLACED owned by the authenticated user",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to CANCELLED, a full refund is issued, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-2",
      "given": "An order in state CONFIRMED owned by the authenticated user",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to CANCELLED, a full refund is issued, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-3",
      "given": "An order in state ASSIGNED (courier assigned, not yet picked up) owned by the authenticated user",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to CANCELLED, a refund minus cancellation fee is issued, the courier is notified, the courier assignment is released, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-4",
      "given": "An order in state PICKED_UP owned by the authenticated user",
      "when": "The user requests cancellation of that order",
      "then": "The cancellation is rejected with an error message directing the user to contact support, and the order state remains PICKED_UP"
    },
    {
      "id": "AC-5",
      "given": "An order in state IN_TRANSIT owned by the authenticated user",
      "when": "The user requests cancellation of that order",
      "then": "The cancellation is rejected with an error message directing the user to contact support, and the order state remains IN_TRANSIT"
    },
    {
      "id": "AC-6",
      "given": "An order in state DELIVERED",
      "when": "The user requests cancellation of that order",
      "then": "The cancellation is rejected with an error indicating the order is already complete and cannot be cancelled"
    },
    {
      "id": "AC-7",
      "given": "An order in state CANCELLED",
      "when": "The user requests cancellation of that order again",
      "then": "The system returns a success response (idempotent), but no additional refund is issued and no duplicate event is emitted"
    },
    {
      "id": "AC-8",
      "given": "An order owned by User A",
      "when": "User B (not an authorized agent) requests cancellation of that order",
      "then": "The cancellation is rejected with an authorization error and the order state is unchanged"
    },
    {
      "id": "AC-9",
      "given": "An order in state ASSIGNED where the courier is en route to pickup",
      "when": "The user cancels and the cancellation succeeds",
      "then": "The courier receives a real-time notification that the order has been cancelled before they arrive at the pickup location"
    },
    {
      "id": "AC-10",
      "given": "An order in a cancellable state and a payment that was already charged",
      "when": "The user requests cancellation",
      "then": "The refund is initiated within the same transactional boundary as the state change — the system never reaches a state where the order is cancelled but the refund is not initiated"
    }
  ],

  "edge_cases": [
    {
      "scenario": "User submits cancellation at the exact moment the order transitions from ASSIGNED to PICKED_UP (race condition)",
      "expected_behavior": "The system must use optimistic locking or equivalent concurrency control. If the state changed between read and write, the cancellation fails with a clear message: 'Order status has changed. Cancellation is no longer available.' The user must not be charged a cancellation fee if the cancellation did not succeed."
    },
    {
      "scenario": "Payment provider is unreachable when processing the refund during cancellation",
      "expected_behavior": "The order transitions to CANCELLED but the refund is queued for retry. The user sees 'Order cancelled — refund is being processed' rather than the cancellation failing entirely. The system must not leave the order in a non-cancelled state because the refund failed — cancellation and refund are logically separate (cancel is immediate, refund is eventually consistent)."
    },
    {
      "scenario": "User cancels an order that has multiple items or partial fulfillment",
      "expected_behavior": "Cancellation applies to the entire order atomically. Partial cancellation (cancelling individual items) is a separate feature. If the system supports partial fulfillment, the cancellable portion depends on which items have been picked up."
    },
    {
      "scenario": "User cancels and then immediately places a new identical order",
      "expected_behavior": "The new order is treated as an entirely separate order with its own lifecycle. No state leaks from the cancelled order. The cancelled order's courier assignment is fully released before the new order could potentially be assigned to the same courier."
    },
    {
      "scenario": "Cancellation request arrives after the cancellation window closes but before the user's UI has refreshed to reflect the new state",
      "expected_behavior": "The backend rejects the cancellation based on current server-side state, not the stale client state. The response includes the current order state so the client can update its UI. The user is not penalized (no fee, no negative account impact) for a request that was valid when they initiated it on the client."
    },
    {
      "scenario": "Courier has already started traveling to the pickup, incurring real costs, but the order is still in ASSIGNED state",
      "expected_behavior": "The cancellation fee in ASSIGNED state exists precisely for this case. The courier is compensated via the fee. The courier is notified immediately to stop traveling. The system does not need to track courier location to determine if cancellation is allowed — the state machine is the source of truth, not GPS."
    },
    {
      "scenario": "User's account has a history of frequent cancellations (potential abuse)",
      "expected_behavior": "Out of scope for the base cancellation feature. Abuse detection is a separate policy concern. However, the OrderCancelled event must include sufficient data (userId, frequency metadata) to enable downstream abuse-detection systems."
    },
    {
      "scenario": "Promotional or discounted order is cancelled",
      "expected_behavior": "Refund amount is based on the amount actually charged, not the pre-discount price. Promotional credits or coupons follow their own restoration rules (e.g., single-use coupons may or may not be restored). This must be clarified with the product team."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly impacts revenue (refunds reduce net revenue), courier compensation (fees for wasted effort), and payment processing costs (refund transactions incur fees from payment providers). A poorly designed cancellation flow — e.g., double refunds from non-idempotent handling — creates direct financial loss. Conversely, an overly restrictive cancellation policy increases chargeback/dispute rates which are far more expensive than voluntary refunds.",
    "operational": "Cancellation affects courier utilization (wasted trips), dispatch optimization (released assignments re-enter the pool), and support load (if self-service cancellation is blocked too early, users flood support channels). Real-time courier notification is critical — a 30-second delay in notification can mean a courier has already arrived at a pickup that no longer exists.",
    "user": "Cancellation flexibility is a top driver of customer trust and repeat usage in logistics platforms. Users who cannot cancel when they expect to will leave negative reviews, initiate chargebacks, and churn. However, users also need clear feedback about fees and restrictions — surprise charges erode trust faster than the inability to cancel.",
    "risk": "Primary risks: (1) Race conditions between cancellation and state transitions causing inconsistent state; (2) Double-refund from non-idempotent handling causing financial loss; (3) Courier not notified causing wasted real-world effort and courier churn; (4) Stale UI state causing user frustration when cancellation is rejected. Compliance risk: refund timelines may be regulated in certain jurisdictions.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Gain self-service cancellation capability, improving trust and control. Must receive clear communication about fees and refund timelines." },
      { "group": "Couriers", "impact": "Affected by mid-assignment cancellations. Must be notified in real-time. Must be compensated fairly via cancellation fees for wasted effort." },
      { "group": "Customer Support", "impact": "Reduced inbound volume for cancellable states. Increased volume for post-pickup states where self-service is blocked. Need tooling to handle escalated cancellations." },
      { "group": "Finance/Accounting", "impact": "Must reconcile refunds, cancellation fees, and payment provider costs. Audit trail from OrderCancelled events feeds into financial reporting." },
      { "group": "Product/Growth", "impact": "Cancellation rate becomes a key metric. Too-easy cancellation may reduce completion rates. Too-hard cancellation increases churn. Must instrument and monitor." }
    ]
  },

  "confidence": {
    "level": 40,
    "reasoning": "The spec is a single sentence with no definition of order states, cancellation windows, fee structures, refund policies, or courier notification requirements. Every business rule above is inferred from standard logistics domain knowledge, not from an actual spec. The PM must validate or override each rule. Key unknowns: exact order state machine, fee amounts, refund timing guarantees, partial fulfillment support, promotional order handling, and jurisdiction-specific refund regulations.",
    "high_confidence_areas": [
      "Terminal states (DELIVERED, CANCELLED) must block cancellation — this is universal",
      "Authorization: only the order owner can cancel — this is a security invariant",
      "Idempotency: duplicate cancellations must not cause duplicate refunds — this is a financial integrity invariant",
      "Courier notification on assigned-order cancellation — this is a physical-world constraint"
    ],
    "low_confidence_areas": [
      "Exact order state machine and which states exist in this system",
      "Cancellation fee amounts and structure",
      "Whether PICKED_UP/IN_TRANSIT should block self-service or allow it with a return-to-sender flow",
      "Refund timing guarantees and whether cancellation + refund are synchronous or eventually consistent",
      "Promotional/coupon restoration policy on cancellation",
      "Jurisdiction-specific refund regulations that may apply"
    ],
    "assumptions": [
      "Order lifecycle includes states: PLACED, CONFIRMED, ASSIGNED, PICKED_UP, IN_TRANSIT, DELIVERED, CANCELLED",
      "Payment is captured at order placement (not on delivery)",
      "Couriers are assigned individually (not batch/route-based)",
      "The system is a logistics/courier platform, not e-commerce with warehouse fulfillment",
      "Self-service cancellation is the scope — admin/support cancellation is separate"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states permit cancellation. The cancellation window is the single most important business decision for this feature and it is entirely unspecified.",
      "affected_stakeholders": ["Customers", "Couriers", "Customer Support", "Finance"],
      "options": [
        "Allow cancellation only before courier assignment (conservative — minimizes courier impact)",
        "Allow cancellation up to pickup (moderate — compensate courier with fee)",
        "Allow cancellation at any pre-delivery state including in-transit with return-to-sender (aggressive — maximizes customer flexibility)"
      ],
      "recommendation": "Option B (allow up to pickup with fee) is the industry standard for courier platforms. Recommend PM confirms this explicitly."
    },
    {
